var stat_data = {};

function $(id){return document.getElementById(id)}

function t(id,val){var el=$(id);if(el)el.textContent=val!=null?String(val):'--'}

function render(){
  var sc=stat_data.selected_character||'';
  var cs=stat_data.characters||{};
  var c=cs[sc]||{};

