  if(hasNsfw){
    $('nsfw').classList.add('on');
    t('body',c.body_state);t('integ',c.clothing_integrity);t('pose',c.pose);
  }
}

function getStatData(){
  if(typeof getAllVariables==='function'){
    try{
      var all=getAllVariables();
      if(all&&all.stat_data&&typeof all.stat_data==='object') stat_data=all.stat_data;
    }catch(e){}
  }
  return stat_data;
}

getStatData();
render();
</script>
